// Prepare identity data matching Identity_map.md schema
const input = $input.first().json.body;

const personaName = input.personaName || 'Default';
const personaType = input.personaType || 'general';
const emails = input.emails || [];
const phones = input.phones || [];
const names = input.names || [];
const usernames = input.usernames || [];
const accounts = input.accounts || [];
const notes = input.notes || '';

// Build description for LLM
let description = `## Identity Data to Ingest\n\n`;
description += `**Persona:** ${personaName} (type: ${personaType})\n\n`;

if (names.length > 0) {
  description += `**Names:** ${names.map(n => `${n.firstName || ''} ${n.lastName || ''}`.trim()).join(', ')}\n`;
}
if (emails.length > 0) {
  description += `**Emails:** ${emails.join(', ')}\n`;
}
if (phones.length > 0) {
  description += `**Phones:** ${phones.join(', ')}\n`;
}
if (usernames.length > 0) {
  description += `**Usernames:** ${usernames.join(', ')}\n`;
}
if (accounts.length > 0) {
  description += `**Accounts:**\n${accounts.map(a => `  - ${a.platform}: ${a.username || a.id}`).join('\n')}\n`;
}
if (notes) {
  description += `**Notes:** ${notes}\n`;
}

return {
  json: {
    personaName,
    personaType,
    emails,
    phones,
    names,
    usernames,
    accounts,
    notes,
    description,
    totalItems: emails.length + phones.length + names.length + usernames.length + accounts.length
  }
};

