// Merge existing context
const inputData = $('2. Prepare Input').first().json;
const neo4jResponse = $input.first().json;

let existingPersona = null;
let existingUser = null;

try {
  if (neo4jResponse.results && neo4jResponse.results[0] && neo4jResponse.results[0].data.length > 0) {
    existingPersona = neo4jResponse.results[0].data[0].row[0];
  }
  if (neo4jResponse.results && neo4jResponse.results[1] && neo4jResponse.results[1].data.length > 0) {
    existingUser = neo4jResponse.results[1].data[0].row[0];
  }
} catch (e) {}

return {
  json: {
    ...inputData,
    existingPersona,
    existingUser,
    isUpdate: existingPersona !== null
  }
};

// Parse and validate the Cypher statements
const aiOutput = $input.first().json.output || $input.first().json.text || '';
const inputData = $('4. Merge Existing Context').first().json;

let statements = [];
let parseError = null;

try {
  // Find JSON array in response
  const jsonMatch = aiOutput.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    statements = JSON.parse(jsonMatch[0]);
  } else {
    parseError = 'No JSON array found in output';
  }
} catch (e) {
  parseError = e.message;
}

// Filter to only valid statements with cypher property
const validStatements = (statements || []).filter(s => 
  s.cypher && 
  typeof s.cypher === 'string' &&
  (s.cypher.toUpperCase().includes('MERGE') || 
   s.cypher.toUpperCase().includes('MATCH') ||
   s.cypher.toUpperCase().includes('CREATE'))
);

return {
  json: {
    personaName: inputData.personaName,
    totalItems: inputData.totalItems,
    statements: validStatements,
    statementCount: validStatements.length,
    parseError: parseError,
    isValid: validStatements.length > 0
  }
};

// Prepare statements for Neo4j HTTP API
const inputData = $input.first().json;
const statements = inputData.statements || [];

// Format for Neo4j transaction API
const neo4jPayload = {
  statements: statements.map(s => ({ statement: s.cypher }))
};

return {
  json: {
    ...inputData,
    neo4jPayload
  }
};

// Process Neo4j response
const neo4jResponse = $input.first().json;
const inputData = $('8. Prepare Neo4j Request').first().json;

let successCount = 0;
let errorCount = 0;
let errors = [];

if (neo4jResponse.body) {
  const body = typeof neo4jResponse.body === 'string' ? JSON.parse(neo4jResponse.body) : neo4jResponse.body;

  if (body.results) {
    successCount = body.results.length;
  }

  if (body.errors && body.errors.length > 0) {
    errorCount = body.errors.length;
    errors = body.errors.map(e => e.message || e.code);
  }
} else if (neo4jResponse.statusCode >= 400) {
  errorCount = inputData.statementCount;
  errors.push(`HTTP ${neo4jResponse.statusCode}`);
} else {
  successCount = inputData.statementCount;
}

return {
  json: {
    success: errorCount === 0,
    personaId: inputData.personaName.toLowerCase().replace(/\s+/g, '_'),
    personaName: inputData.personaName,
    entitiesCreated: successCount,
    errorsCount: errorCount,
    errors: errors.slice(0, 5),
    totalItems: inputData.totalItems,
    method: 'llm-http'
  }
};

// Error response for invalid Cypher
const inputData = $input.first().json;

return {
  json: {
    success: false,
    personaId: null,
    personaName: inputData.personaName,
    entitiesCreated: 0,
    method: 'llm-http',
    error: inputData.parseError || 'Generated Cypher was invalid or empty',
    message: `Failed to create entities for persona ${inputData.personaName}`
  }
};
